def solve(*args):
    if len(args) < 2:
        raise ValueError("At least two arguments are required.")

    # Assuming the first argument is the operation and the rest are numbers
    operation = args[0]
    numbers = args[1:]

    if operation == 'add':
        return sum(numbers)
    elif operation == 'subtract':
        return numbers[0] - sum(numbers[1:])
    elif operation == 'multiply':
        result = 1
        for number in numbers:
            result *= number
        return result
    elif operation == 'divide':
        if 0 in numbers[1:]:
            raise ValueError("Cannot divide by zero.")
        result = numbers[0]
        for number in numbers[1:]:
            result /= number
        return result
    else:
        raise ValueError("Invalid operation. Supported operations: add, subtract, multiply, divide.")
